import { createSignal } from 'solid-js';

const [openIds, setOpenIds] = createSignal<ReadonlySet<string>>(new Set(), { equals: false });

export const dropdownStore = {
  openIds,
  open: (id: string) =>
    setOpenIds(prev => {
      if (prev.has(id)) return prev;
      const next = new Set(prev);
      next.add(id);
      return next;
    }),
  close: (id: string) =>
    setOpenIds(prev => {
      if (!prev.has(id)) return prev;
      const next = new Set(prev);
      next.delete(id);
      return next;
    }),
  closeAll: () => setOpenIds(new Set<string>()),
  isOpen: (id: string) => openIds().has(id),
};
